'use client';

import { useForm } from '@tanstack/react-form';
import { api } from '@workspace/backend/api';
import type { Id } from '@workspace/backend/dataModel';
import { Button } from '@workspace/ui/components/button';
import {
	Dialog,
	DialogClose,
	DialogContent,
	DialogFooter,
	DialogHeader,
	DialogPanel,
	DialogTitle,
	DialogTrigger,
} from '@workspace/ui/components/dialog';
import { Field, FieldError, FieldLabel } from '@workspace/ui/components/field';
import { Input } from '@workspace/ui/components/input';
import {
	InputGroup,
	InputGroupAddon,
	InputGroupInput,
	InputGroupText,
} from '@workspace/ui/components/input-group';
import { toastManager } from '@workspace/ui/components/toast';
import { useMutation, useQuery } from 'convex/react';
import { type ReactElement, useState } from 'react';
import InclusionCategoryCombobox from '@/components/inclusions/inclusion-category-combobox';
import { defaultInclusionCategoryCodeFromName } from '@/components/inclusions/inclusion-category-form-shared';
import {
	emptyInclusionFormValues,
	inclusionFormFieldError,
	inclusionFormSchema,
	parseMoneyString,
} from '@/components/inclusions/inclusion-form-shared';
import UnitCombobox from '@/components/inclusions/unit-combobox';
import { getConvexErrorMessage } from '@/lib/convex-errors';

const FORM_ID = 'add-inclusion-form';

export default function AddInclusion({
	initialCategoryId,
	trigger,
}: {
	initialCategoryId?: Id<'inclusionCategories'>;
	trigger?: ReactElement;
} = {}) {
	const [open, setOpen] = useState(false);
	const categories = useQuery(api.inclusionCategories.list.list, {});
	const units = useQuery(api.units.list.list, {});
	const addInclusion = useMutation(api.inclusions.add.add);
	const addCategory = useMutation(api.inclusionCategories.add.add);

	const form = useForm({
		defaultValues: emptyInclusionFormValues,
		validators: {
			onChange: inclusionFormSchema as never,
		},
		onSubmit: async ({ value }) => {
			try {
				const parsed = inclusionFormSchema.parse(value);
				let resolvedCategoryId: Id<'inclusionCategories'>;

				const newName = parsed.newCategoryName?.trim();
				if (newName) {
					const code = defaultInclusionCategoryCodeFromName(newName);
					resolvedCategoryId = await addCategory({ name: newName, code });
				} else {
					resolvedCategoryId = parsed.categoryId as Id<'inclusionCategories'>;
				}

				const standardPriceStr = parsed.standardPrice?.trim();
				const standardPrice = standardPriceStr
					? parseMoneyString(standardPriceStr)
					: undefined;
				const standardLabourPriceStr = parsed.standardLabourPrice?.trim();
				const standardLabourPrice = standardLabourPriceStr
					? parseMoneyString(standardLabourPriceStr)
					: undefined;
				const measurementUnit = parsed.measurementUnit?.trim() || undefined;
				await addInclusion({
					categoryId: resolvedCategoryId,
					title: parsed.title,
					standardPrice,
					standardLabourPrice,
					measurementUnit: measurementUnit as never,
				});
				toastManager.add({
					title: 'Inclusion added',
					type: 'success',
				});
				form.reset();
				setOpen(false);
			} catch (error) {
				toastManager.add({
					description: getConvexErrorMessage(
						error,
						'Could not add inclusion. Please try again in a moment.'
					),
					title: 'Could not add inclusion',
					type: 'error',
				});
				form.reset();
				setOpen(false);
			}
		},
	});

	return (
		<Dialog
			onOpenChange={(nextOpen) => {
				setOpen(nextOpen);
				if (nextOpen) {
					form.reset(
						{
							...emptyInclusionFormValues,
							categoryId: initialCategoryId ?? '',
						},
						{ keepDefaultValues: true }
					);
				} else {
					form.reset();
				}
			}}
			open={open}
		>
			<DialogTrigger render={trigger ?? <Button>Add Inclusion</Button>} />
			<DialogContent>
				<DialogHeader>
					<DialogTitle>Add Inclusion</DialogTitle>
				</DialogHeader>
				<form
					id={FORM_ID}
					onSubmit={(event) => {
						event.preventDefault();
						form.handleSubmit().catch(() => {
							/* TanStack Form handles validation */
						});
					}}
				>
					<DialogPanel className="flex flex-col gap-4">
						<form.Field name="title">
							{(field) => {
								const invalid =
									field.state.meta.isTouched && !field.state.meta.isValid;
								return (
									<Field data-invalid={invalid}>
										<FieldLabel htmlFor={field.name}>Title</FieldLabel>
										<Input
											aria-invalid={invalid}
											autoFocus
											id={field.name}
											name={field.name}
											nativeInput
											onBlur={field.handleBlur}
											onChange={(e) => field.handleChange(e.target.value)}
											placeholder="Inclusion title"
											value={field.state.value}
										/>
										{invalid ? (
											<FieldError>
												{inclusionFormFieldError(field.state.meta.errors)}
											</FieldError>
										) : null}
									</Field>
								);
							}}
						</form.Field>
						<form.Field name="categoryId">
							{(field) => {
								const invalid =
									field.state.meta.isTouched && !field.state.meta.isValid;
								return (
									<Field data-invalid={invalid}>
										<FieldLabel htmlFor={field.name}>Category</FieldLabel>
										<InclusionCategoryCombobox
											categories={categories}
											id={field.name}
											invalid={invalid}
											onBlur={field.handleBlur}
											onChange={(next) => field.handleChange(next)}
											placeholder="Select a category"
											value={field.state.value}
										/>
										{invalid ? (
											<FieldError>
												{inclusionFormFieldError(field.state.meta.errors)}
											</FieldError>
										) : null}
									</Field>
								);
							}}
						</form.Field>
						<form.Field name="newCategoryName">
							{(field) => (
								<Field>
									<FieldLabel htmlFor={field.name}>
										Or create new category
									</FieldLabel>
									<Input
										id={field.name}
										name={field.name}
										nativeInput
										onBlur={field.handleBlur}
										onChange={(e) => field.handleChange(e.target.value)}
										placeholder="New category name"
										value={field.state.value ?? ''}
									/>
								</Field>
							)}
						</form.Field>
						<div className="grid grid-cols-2 gap-4">
							<form.Field name="standardPrice">
								{(field) => {
									const invalid =
										field.state.meta.isTouched && !field.state.meta.isValid;
									return (
										<Field data-invalid={invalid}>
											<FieldLabel htmlFor={field.name}>
												Standard Base Price
											</FieldLabel>
											<InputGroup>
												<InputGroupAddon align="inline-start">
													<InputGroupText>$</InputGroupText>
												</InputGroupAddon>
												<InputGroupInput
													aria-invalid={invalid || undefined}
													id={field.name}
													inputMode="decimal"
													nativeInput
													onBlur={field.handleBlur}
													onChange={(e) => field.handleChange(e.target.value)}
													placeholder="0.00"
													type="text"
													value={field.state.value ?? ''}
												/>
												<InputGroupAddon align="inline-end">
													<InputGroupText>AUD</InputGroupText>
												</InputGroupAddon>
											</InputGroup>
											{invalid ? (
												<FieldError>
													{inclusionFormFieldError(field.state.meta.errors)}
												</FieldError>
											) : null}
										</Field>
									);
								}}
							</form.Field>
							<form.Field name="standardLabourPrice">
								{(field) => {
									const invalid =
										field.state.meta.isTouched && !field.state.meta.isValid;
									return (
										<Field data-invalid={invalid}>
											<FieldLabel htmlFor={field.name}>
												Standard Labour Price
											</FieldLabel>
											<InputGroup>
												<InputGroupAddon align="inline-start">
													<InputGroupText>$</InputGroupText>
												</InputGroupAddon>
												<InputGroupInput
													aria-invalid={invalid || undefined}
													id={field.name}
													inputMode="decimal"
													nativeInput
													onBlur={field.handleBlur}
													onChange={(e) => field.handleChange(e.target.value)}
													placeholder="0.00"
													type="text"
													value={field.state.value ?? ''}
												/>
												<InputGroupAddon align="inline-end">
													<InputGroupText>AUD</InputGroupText>
												</InputGroupAddon>
											</InputGroup>
											{invalid ? (
												<FieldError>
													{inclusionFormFieldError(field.state.meta.errors)}
												</FieldError>
											) : null}
										</Field>
									);
								}}
							</form.Field>
							<form.Field name="measurementUnit">
								{(field) => (
									<Field>
										<FieldLabel htmlFor={field.name}>Unit</FieldLabel>
										<UnitCombobox
											id={field.name}
											onBlur={field.handleBlur}
											onChange={(next) => field.handleChange(next)}
											units={units}
											value={field.state.value ?? ''}
										/>
									</Field>
								)}
							</form.Field>
						</div>
					</DialogPanel>
				</form>
				<DialogFooter>
					<DialogClose render={<Button type="button" variant="outline" />}>
						Cancel
					</DialogClose>
					<Button
						disabled={
							!(
								form.state.isValid &&
								!form.state.isValidating &&
								!form.state.isSubmitting
							)
						}
						form={FORM_ID}
						type="submit"
					>
						Add Inclusion
					</Button>
				</DialogFooter>
			</DialogContent>
		</Dialog>
	);
}
